import { Component, signal } from '@angular/core';
import { AXDonutChartComponent } from '@acorex/charts/donut-chart';
import { AXDonutChartData } from '@acorex/charts/donut-chart';
import { AXDonutChartOption } from '@acorex/charts/donut-chart';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive Donut Chart</h2>
      <ax-donut-chart 
        [data]="showcaseData()" 
        [options]="showcaseOptions()"
        (segmentClick)="onSegmentClick($event)"
        (segmentHover)="onSegmentHover($event)"
      />
      <div class="chart-info">
        <p>Click on segments to interact with the chart</p>
      </div>
    </div>
  `,
  imports: [AXDonutChartComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
      text-align: center;
    }
    .chart-info {
      margin-top: 1rem;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class DonutChartShowcaseComponent {
  showcaseData = signal<AXDonutChartData[]>([
    { id: 'sales', label: 'Sales', value: 40, color: '#3498db' },
    { id: 'marketing', label: 'Marketing', value: 25, color: '#e74c3c' },
    { id: 'development', label: 'Development', value: 20, color: '#2ecc71' },
    { id: 'support', label: 'Support', value: 15, color: '#f39c12' }
  ]);

  showcaseOptions = signal<AXDonutChartOption>({
    width: 400,
    height: 400,
    showTooltip: true,
    donutWidth: 40,
    cornerRadius: 8,
    animationDuration: 1500,
    animationEasing: 'ease-in-out'
  });

  onSegmentClick(segment: AXDonutChartData): void {
    console.log('Segment clicked:', segment);
  }

  onSegmentHover(segment: AXDonutChartData | null): void {
    console.log('Segment hover:', segment);
  }
}
